{
  "title": "Understanding Cold Sensations and Fever Management",
  "description": "This course provides essential knowledge and practical strategies for recognizing and managing symptoms associated with feeling cold and having a fever, particularly in the context of a cough.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Body Temperature Regulation",
      "description": "Explore how the body regulates temperature, the significance of feeling cold, and the physiological processes involved in fever."
    },
    {
      "id": "module2",
      "title": "Identifying Symptoms and Their Implications",
      "description": "Learn to identify common symptoms associated with fever and cold sensations, including cough, and understand their potential causes."
    },
    {
      "id": "module3",
      "title": "Monitoring and Measuring Temperature",
      "description": "Gain skills in accurately measuring body temperature and interpreting results, including understanding what a fever signifies."
    },
    {
      "id": "module4",
      "title": "Management Strategies for Fever and Cold Symptoms",
      "description": "Discover effective management strategies for dealing with fever and cold symptoms, including home remedies, when to seek medical attention, and self-care practices."
    }
  ]
}
